#include<bits/stdc++.h>
using namespace std;
double f[5050][5050];
bitset<10050> vis[10050];
double calc(int x)
{
	return x*(x-1)/2.0;
}
double ds(double x)
{
	return 1.0/x;
}
double xf(double x)
{
	return -x;
}
double dp(int n,int m)
{
    if(n<=0||m<0||n<m)
    {
        return 0;
    }
	if(vis[n][m])
	{
		return f[n][m];
	}
	double &v=f[n][m];
	double dp1;
    dp1=(((dp(n-1,m-1)+1)-(dp(n-1,m-1)+1)*(m-1)-2*(n-m)*dp(n,m+1))/(n*2-m));
    double dp2;
    dp2=((n-m)*(dp(n-1,m)+1)-m*(m-1)/2*(dp(n-2,m-2)+2)-2*m*(n-m)*(dp(n-1,m)+1)-2*(n-m)*(n-m-1)*dp(n,m+2))*2.0/(n*2-m)/(n*2-m-1);
    v=max({dp1,dp2,0.0});
	vis[n][m]=true;
	return v;
}
int main()
{
	int t;
	scanf("%d",&t);
	while(t--)
	{
		int n,m;
		scanf("%d%d",&n,&m);
		printf("%.9lf\n",dp(n,m)/2.0+n/2.0);
	}
	return 0;
}
